import React, { useState, useEffect } from 'react';
import { Alert, Card, Button, Table, Modal, Form } from 'antd'; // Assuming AntD based on UI snippet

const LeavePage = ({ employeeId }) => {
  const [balances, setBalances] = useState([]);
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    // Integration: Get real balances from schema [cite: 64, 65]
    const [balRes, reqRes] = await Promise.all([
      fetch(`/api/leaves/balances/${employeeId}`),
      fetch(`/api/leaves/requests/${employeeId}`)
    ]);
    setBalances(await balRes.json());
    setRequests(await reqRes.json());
    setLoading(false);
  };

  const handleSubmit = async (values) => {
    try {
      const response = await fetch('/api/leaves/request', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...values, employeeId })
      });

      if (!response.ok) {
        const err = await response.json();
        throw new Error(err.message); // Displays policy violation (Tenure/Notice) 
      }

      Alert.success("Request submitted successfully");
      fetchData();
    } catch (error) {
      Alert.error(error.message);
    }
  };

  return (
    <div className="leave-module">
      {/* Balance Overview [cite: 64] */}
      <div className="balance-grid">
        {balances.map(b => (
          <Card key={b.LeaveTypeID} title={b.LeaveType.LeaveTypeName} 
                style={{ borderLeft: `5px solid ${b.LeaveType.DisplayColor}` }}>
            <p>Available: <b>{b.EntitledDays + b.CarryOverDays - b.UsedDays - b.PendingDays}</b></p>
            <p><small>Pending Approval: {b.PendingDays}</small></p>
          </Card>
        ))}
      </div>

      {/* History Table [cite: 68, 76] */}
      <Table 
        dataSource={requests} 
        columns={[
          { title: 'Type', dataIndex: ['LeaveType', 'LeaveTypeName'] },
          { title: 'Period', render: (r) => `${r.StartDate} to ${r.EndDate}` },
          { title: 'Days', dataIndex: 'TotalDays' },
          { title: 'Status', dataIndex: 'Status', render: (s) => (
            <span className={`status-badge ${s.toLowerCase()}`}>{s}</span>
          )}
        ]}
      />
    </div>
  );
};
